// 2. Declaración e inicialización de una constante con 'const'
const ANIO_NACIMIENTO = 2000;
console.log("Año de nacimiento registrado:", ANIO_NACIMIENTO);

// NOTA DE DEPURACIÓN: Intentar cambiar una constante provocará un error en la consola:
// ANIO_NACIMIENTO = 2005; // Descomentar esta línea rompería la ejecución de la app

// Declaración de distintos tipos primitivos
const nombreUsuario = "María"; // String (Cadenas de texto siempre entre comillas)
let edadUsuario = 28; // Number (Número entero)
let precioProducto = 19.99; // Number (Número decimal)

let estaConectado = true; // Boolean (Verdadero)

// Demostración práctica de Undefined y Null
let direccion; // Al declararla pero no asignarle valor, JavaScript le aplica 'undefined'
let carritoCompras = null; // Lo definimos intencionalmente como vacío (nulo)

// Comprobación de los datos imprimiéndolos en la consola
