// =========================================================
// 1. EJEMPLOS DE OPERADORES ARITMÉTICOS
// =========================================================
const precioCamisa = 25;
const precioPantalon = 40;
const totalCompra = precioCamisa + precioPantalon;
console.log("Depuración - Total de la compra:", totalCompra);

const nombre = "Ana";
const saludo = "Hola, " + nombre + "!"; // Concatenación de textos
console.log("Depuración - Mensaje unido:", saludo);

// =========================================================
// 2. EJEMPLOS DE OPERADORES DE COMPARACIÓN
// =========================================================
const edadUsuario = 20;
const esMayorDeEdad = edadUsuario >= 18;
console.log("Depuración - ¿El usuario es mayor de edad?:", esMayorDeEdad);

// Comprobación de igualdad estricta
const claveCorrecta = "1234";
const intentoUsuario = "1234";
const accesoConcedido = (claveCorrecta === intentoUsuario);
console.log("Depuración - ¿La clave coincide?:", accesoConcedido);

// =========================================================
// 3. EJEMPLOS DE OPERADORES LÓGICOS
// =========================================================
const tieneEntrada = true;
const vieneConUnAdulto = false;

// Uso de OR (||): El menor entra si tiene entrada O si viene acompañado
const puedeEntrarAlCine = tieneEntrada || vieneConUnAdulto;
console.log("Depuración - ¿Puede entrar al cine?:", puedeEntrarAlCine);

// Uso de NOT (!): Invierte el estado de una variable
const controlLucesEncendidas = true;
console.log("Depuración - Estado inverso de las luces:", !controlLucesEncendidas);

// =========================================================
// 1. EJEMPLO CON IF, ELSE IF, ELSE
// =========================================================
const edadPersona = 16;

console.log("Depuración - Iniciando evaluación de edad:", edadPersona);

if (edadPersona >= 18) {
    // Este bloque solo se ejecuta si la comparación da 'true'
    console.log("Resultado: Es mayor de edad. Acceso concedido.");
} else if (edadPersona >= 15) {
    // Se evalúa solo si el primer 'if' falló y esta condición es 'true'
    console.log("Resultado: Es menor de edad, pero tiene permiso juvenil.");
} else {
    // Se ejecuta por defecto si absolutamente todo lo anterior dio 'false'
    console.log("Resultado: Es menor de edad. Acceso denegado.");
}

// =========================================================
// 2. EJEMPLO CON SWITCH
// =========================================================
const metodoPago = "tarjeta";

console.log("Depuración - Evaluando método de pago seleccionado:", metodoPago);

switch (metodoPago) {
    case "efectivo":
        console.log("Acción: Prepare el dinero en mano para el repartidor.");
        break; // Detiene la evaluación del switch
    case "tarjeta":
        console.log("Acción: Redirigiendo a la pasarela bancaria segura...");
        break;
    case "paypal":
        console.log("Acción: Abriendo ventana de inicio de sesión de PayPal...");
        break;
    default:
        // El caso 'default' actúa como el 'else', se ejecuta si ningún caso coincidió
        console.log("Error: Método de pago no reconocido por el sistema.");
        break;
}

// =========================================================
// 1. EJEMPLO CON BUCLE 'FOR'
// =========================================================
console.log("Depuración - Iniciando bucle FOR...");

// i = 1 (inicio); i <= 5 (condición); i++ (incrementar i en 1 en cada vuelta)
for (let i = 1; i <= 5; i++) {
    console.log("Vuelta número (FOR):", i);
}

// =========================================================
// 2. EJEMPLO CON BUCLE 'WHILE'
// =========================================================
console.log("\nDepuración - Iniciando bucle WHILE...");

let tazasDeCafe = 3;

// Se ejecuta MIENTRAS nos quede café disponible
while (tazasDeCafe > 0) {
    console.log("Tomando una taza de café. Quedan:", tazasDeCafe);

    // CRUCIAL: Modificamos la variable para evitar un bucle infinito
    tazasDeCafe--; 
}
console.log("Condición finalizada: El café se ha agotado.");

// =========================================================
// 3. EJEMPLO CON BUCLE 'DO-WHILE'
// =========================================================
console.log("\nDepuración - Iniciando bucle DO-WHILE...");

let bateriaCelular = 0;

// Aunque la batería está en 0 (la condición es falsa desde el inicio),
// el bloque se ejecutará una vez de manera obligatoria.
do {
    console.log("El sistema operativo está intentando arrancar...");
} while (bateriaCelular > 0);

console.log("Condición evaluada al final: Teléfono apagado por falta de batería.");

// =========================================================
// 1. DECLARACIÓN DE LA FUNCIÓN (Se construye la máquina)
// =========================================================
// Esta función recibe dos parámetros de entrada: 'nombre' y 'apellido'
function crearSaludoFormal(nombre, apellido) {
    console.log("Depuración - Entrando a la función con:", nombre, apellido);

    // Procesamos los datos internamente creando un mensaje personalizado
    const saludoCompleto = "Estimado/a " + nombre + " " + apellido + ", es un placer saludarle.";

    // Devolvemos el resultado final al exterior
    return saludoCompleto;
}

// =========================================================
// 2. INVOCACIÓN O LLAMADA A LA FUNCIÓN (Se usa la máquina)
// =========================================================
console.log("\nDepuración - Iniciando llamadas a funciones...");

// Llamada 1: Guardamos el retorno de la función en una nueva variable
const saludoCliente1 = crearSaludoFormal("Carlos", "Mendoza");
console.log("Resultado 1:", saludoCliente1);

// Llamada 2: Podemos reutilizar la misma función cambiando los argumentos
const saludoCliente2 = crearSaludoFormal("Elena", "Gómez");
console.log("Resultado 2:", saludoCliente2);

// =========================================================
// 3. FUNCIÓN SIN RETORNO (Solo realiza una acción interna)
// =========================================================
function mostrarAlertaConsola(mensaje) {
    console.log("⚠️ ALERTA DEL SISTEMA: " + mensaje);
    // Al no tener 'return', si intentamos guardar el resultado de esta función,
    // obtendremos un tipo de dato 'undefined'.
}

// Invocamos la función de alerta
mostrarAlertaConsola("La sesión del usuario está a punto de expirar.");

// Variable con datos de prueba
const nombreProducto = "Teclado Mecánico";
const precio = 49.99;

// 1. FORMA ANTIGUA (Concatenación tradicional con +)
const mensajeAntiguo = "El artículo " + nombreProducto + " tiene un costo de $" + precio + " euros.";
console.log("Depuración (Antiguo):", mensajeAntiguo);

// 2. FORMA MODERNA (Template Literals con comillas invertidas)
// Observe cómo el código es mucho más limpio, legible y natural de escribir
const mensajeModerno = `El artículo ${nombreProducto} tiene un costo de $${precio} euros.`;
console.log("Depuración (Moderno):", mensajeModerno);

// Los Template Literals también respetan los saltos de línea sin usar '\n'
const facturaMultiLinea = `
--- DETALLE DE FACTURA ---
Producto: ${nombreProducto}
Total: $${precio}
--------------------------`;
console.log(facturaMultiLinea);

// =========================================================
// 1. CREACIÓN Y MANIPULACIÓN BÁSICA
// =========================================================
const frutas = ["Manzana", "Plátano", "Kiwi"];
console.log("Depuración - Lista inicial:", frutas);
console.log("Depuración - Cantidad de elementos:", frutas.length);

frutas.push("Naranja"); // Añade al final
console.log("Depuración - Lista tras el push:", frutas);

// =========================================================
// 2. MÉTODOS ESENCIALES (El poder de la iteración moderna)
// =========================================================
const preciosEuros = [10, 20, 35, 50, 80];
console.log("\nDepuración - Precios base (Original):", preciosEuros);

// Ej 1: .map() -> Convertir los precios a dólares (multiplicando por 1.10)
const preciosDolares = preciosEuros.map(precio => precio * 1.10);
console.log("Resultado .map() - Precios en Dólares:", preciosDolares);

// Ej 2: .filter() -> Seleccionar solo los precios que sean mayores de 30 euros
const preciosAltos = preciosEuros.filter(precio => precio > 30);
console.log("Resultado .filter() - Precios caros:", preciosAltos);

// Ej 3: .reduce() -> Sumar todos los precios de la lista para obtener el total
// El '0' al final es el valor inicial en el que empieza el acumulador
const sumaTotal = preciosEuros.reduce((acumulador, precioActual) => {
    console.log(`-> Procesando reduce: Acumulado=${acumulador}, ElementoActual=${precioActual}`);
    return acumulador + precioActual;
}, 0);

console.log("Resultado .reduce() - Suma total de la factura:", sumaTotal);
console.log("Comprobación final: El array original sigue intacto:", preciosEuros);

// =========================================================
// 1. CREACIÓN DE UN OBJECTO LITERAL
// =========================================================
const smartphone = {
    // Propiedades (Características del objeto)
    marca: "Apple",
    modelo: "iPhone 15",
    color: "Negro Titanio",
    bateriaPorcentaje: 85,
    estaEncendido: true,

    // Métodos (Acciones que el objeto sabe realizar)
    tomarFoto: function() {
        console.log("📸 ¡Clic! Foto guardada en la galería.");
    },

    mostrarEstado: function() {
        // Usamos 'this' para leer las propiedades de este mismo objeto
        console.log(`Dispositivo: ${this.marca} ${this.modelo} | Batería: ${this.bateriaPorcentaje}%`);
    }
};

// =========================================================
// 2. ACCESO Y MODIFICACIÓN (Lectura y Escritura)
// =========================================================
console.log("\nDepuración - Iniciando pruebas con objetos...");

// Lectura usando la notación de punto
console.log("Marca del teléfono:", smartphone.marca);

// Modificación de una propiedad existente
smartphone.bateriaPorcentaje = 84;
console.log("Depuración - Batería actualizada:", smartphone.bateriaPorcentaje);

// Añadir una propiedad completamente nueva sobre la marcha
smartphone.tiene5G = true;
console.log("Depuración - Objeto modificado:", smartphone);

// =========================================================
// 3. EJECUCIÓN DE MÉTODOS (Invocación de acciones)
// =========================================================
console.log("\nDepuración - Ejecutando métodos del objeto:");
smartphone.tomarFoto();
smartphone.mostrarEstado();

// =========================================================
// 1. DESTRUCTURING (Desestructuración)
// =========================================================
console.log("Depuración - Iniciando pruebas de Destructuring...");

const usuario = { nombre: "Lucas", rol: "Admin", pais: "España" };
// Extraemos las propiedades directamente en variables independientes
const { nombre, rol } = usuario;
console.log(`Variables extraídas -> Nombre: ${nombre}, Rol: ${rol}`);

const colores = ["Rojo", "Verde", "Azul"];
// En arrays se extrae por orden de posición de índice
const [primerColor, segundoColor] = colores;
console.log(`Colores extraídos -> Primero: ${primerColor}, Segundo: ${segundoColor}`);

// =========================================================
// 2. SPREAD OPERATOR (Esparcir / Clonar)
// =========================================================
console.log("\nDepuración - Iniciando pruebas de Spread (...)");

const listaPrecios1 = [10, 20];
const listaPrecios2 = [30, 40];

// Fusionamos ambos arrays y añadimos un elemento extra sobre la marcha
const todosLosPrecios = [...listaPrecios1, ...listaPrecios2, 50];
console.log("Array combinado con Spread:", todosLosPrecios);

// Clonación segura de un objeto (Evita modificar el original por referencia)
const copiaUsuario = { ...usuario, conectado: true };
console.log("Objeto clonado y expandido:", copiaUsuario);

// =========================================================
// 3. REST PARAMETER (Agrupar sobrantes)
// =========================================================
console.log("\nDepuración - Iniciando pruebas de Rest (...)");

const notasExamenes = [9, 8, 4, 7, 6];
// Capturamos las dos primeras notas y agrupamos el 'resto' en un array
const [matricula, sobresaliente, ...otrasNotas] = notasExamenes;

console.log(`Mejor nota: ${matricula}`);
console.log(`Segunda mejor: ${sobresaliente}`);
console.log("Array de notas restantes (capturadas por Rest):", otrasNotas);

// =========================================================
// 1. COMPARATIVA: TRADICIONAL VS FLECHA
// =========================================================

// Función tradicional
function duplicarTradicional(numero) {
    return numero * 2;
}
console.log("Depuración (Tradicional):", duplicarTradicional(5));

// Función de flecha equivalente con RETORNO IMPLÍCITO
// Al ser una sola línea, no necesita llaves { } ni la palabra 'return'
const duplicarFlecha = numero => numero * 2;
console.log("Depuración (Flecha moderna):", duplicarFlecha(5));

// =========================================================
// 2. COMPORTAMIENTO CON MÚLTIPLES LÍNEAS
// =========================================================
// Si la función de flecha requiere más de una línea de lógica,
// las llaves { } y el 'return' vuelven a ser obligatorios.
const calcularPrecioConIva = (precioBase, impuesto) => {
    console.log("Depuración - Calculando impuestos para:", precioBase);
    const total = precioBase + (precioBase * impuesto);
    return total;
};
console.log("Precio final:", calcularPrecioConIva(100, 0.21));

// =========================================================
// 3. EL PELIGRO DE 'THIS' EN ARROW FUNCTIONS
// =========================================================
const heroe = {
    nombreReal: "Bruce Wayne",
    // Método tradicional: funciona correctamente con 'this'
    obtenerNombreTradicional: function() {
        return `El héroe es ${this.nombreReal}`;
    },
    // Método flecha: Rompe el 'this' porque intenta buscarlo fuera del objeto
    obtenerNombreFlecha: () => {
        return `El héroe es ${this.nombreReal}`;
    }
};

console.log("\nDepuración - Probando contextos de 'this':");
console.log("Resultado Tradicional:", heroe.obtenerNombreTradicional()); 
console.log("Resultado Flecha (Dará undefined):", heroe.obtenerNombreFlecha());

// =========================================================
// 1. DEFINICIÓN DEL MOLDE (La Clase)
// =========================================================
class Vehiculo {
    // El constructor recibe los parámetros iniciales para personalizar cada objeto
    constructor(marca, modelo, color) {
        console.log(`Depuración - Ejecutando constructor para un nuevo ${marca}...`);

        // Asignamos los valores a las propiedades del objeto usando 'this'
        this.marca = marca;
        this.modelo = modelo;
        this.color = color;
        this.estaEncendido = false; // Propiedad inicial por defecto
    }

    // Método: Acción que todos los vehículos creados sabrán realizar
    encenderMotor() {
        this.estaEncendido = true;
        console.log(`Depuración - [${this.marca} ${this.modelo}]: El motor ha arrancado.`);
    }

    mostrarInformacion() {
        const estado = this.estaEncendido ? "Encendido" : "Apagado";
        console.log(`Vehículo: ${this.marca} ${this.modelo} | Color: ${this.color} | Estado: ${estado}`);
    }
}

// =========================================================
// 2. CREACIÓN DE INSTANCIAS (Objetos reales basados en el molde)
// =========================================================
console.log("Iniciando la fabricación de vehículos...\n");

// Creamos el primer objeto real (Instancia 1)
const miAuto = new Vehiculo("Toyota", "Corolla", "Rojo");

// Creamos un segundo objeto completamente independiente (Instancia 2)
const autoCliente = new Vehiculo("Hyundai", "i30", "Gris");

// =========================================================
// 3. USO DE LAS INSTANCIAS Y DEPURACIÓN
// =========================================================
console.log("\n--- Interactuando con las instancias ---");

// Cada objeto mantiene su propio estado de forma aislada
miAuto.encenderMotor();
miAuto.mostrarInformacion();

// El segundo objeto sigue apagado porque no hemos llamado a su método
autoCliente.mostrarInformacion();

// =========================================================
// PILAR 1 Y 2: ENCAPSULAMIENTO Y ABSTRACCIÓN
// =========================================================
class CuentaBancaria {
    // Propiedad privada (#): Nadie puede modificarla directamente desde fuera
    #saldo;

    constructor(titular, saldoInicial) {
        this.titular = titular;
        this.#saldo = saldoInicial;
    }

    // Abstracción: El exterior solo ve el método simplificado 'depositar'
    depositar(monto) {
        if (monto > 0) {
            this.#saldo += monto;
            console.log(`Depuración - [Cuenta de ${this.titular}]: Depósito de $${monto} procesado con éxito.`);
        } else {
            console.log("⚠️ Error: El monto a depositar debe ser mayor a cero.");
        }
    }

    // Mecanismo seguro (Getter) para exponer el valor privado bajo control
    obtenerSaldoActual() {
        return this.#saldo;
    }
}

// =========================================================
// PILAR 3 Y 4: HERENCIA Y POLIMORFISMO
// =========================================================
// Clase Padre (Base)
class Empleado {
    constructor(nombre, salarioBase) {
        this.nombre = nombre;
        this.salarioBase = salarioBase;
    }

    // Método base que será polimorfado
    calcularPago() {
        return this.salarioBase;
    }
}

// Herencia: Desarrollador hereda de Empleado usando 'extends'
class Desarrollador extends Empleado {
    constructor(nombre, salarioBase, bonoProyecto) {
        // 'super' inicializa las propiedades heredadas del padre
        super(nombre, salarioBase);
        this.bonoProyecto = bonoProyecto;
    }

    // Polimorfismo: Sobreescribimos el método 'calcularPago' con lógica propia
    calcularPago() {
        console.log(`Depuración - Calculando nómina especial para Desarrollador: ${this.nombre}`);
        return this.salarioBase + this.bonoProyecto;
    }
}

// =========================================================
// PRUEBAS DE EJECUCIÓN Y DEPURACIÓN
// =========================================================
console.log("--- Probando Encapsulamiento ---");
const miCuenta = new CuentaBancaria("Juan Pérez", 500);
miCuenta.depositar(200);
// miCuenta.#saldo = 1000000; // ❌ ERROR: Provoca fallo sintáctico, el saldo está protegido
console.log("Saldo final verificado:", miCuenta.obtenerSaldoActual());

console.log("\n--- Probando Herencia y Polimorfismo ---");
const empleadoComun = new Empleado("Ana Gómez", 1500);
const desarrolladorSenior = new Desarrollador("Carlos Ruiz", 2500, 600);

// Ambos responden al mismo método, pero ejecutan cálculos distintos (Polimorfismo)
console.log(`Pago de Ana: $${empleadoComun.calcularPago()}`);
console.log(`Pago de Carlos: $${desarrolladorSenior.calcularPago()}`);

// =========================================================
// REPRESENTACIÓN DEL HTML REQUISITO PARA ESTE CÓDIGO:
// <h1 id="titulo-principal">Texto original</h1>
// <button class="btn-accion">Cambiar interfaz</button>
// =========================================================

console.log("Depuración - Iniciando manipulación del DOM...");

// 1. SELECCIÓN DE ELEMENTOS
// Seleccionamos por ID utilizando el símbolo '#'
const titulo = document.querySelector("#titulo-principal");

// Seleccionamos por clase utilizando el símbolo '.'
const boton = document.querySelector(".btn-accion");

console.log("Depuración - Elemento título capturado:", titulo);
console.log("Depuración - Elemento botón capturado:", boton);

// Comprobación de seguridad para evitar fallos si el HTML cambia
if (titulo && boton) {

    // 2. MODIFICACIÓN DINÁMICA DE CONTENIDO
    // Cambiamos el texto interno de forma segura
    titulo.textContent = "¡Interfaz Actualizada con JavaScript!";
    console.log("Depuración - Texto del título modificado correctamente.");

    // 3. MODIFICACIÓN DIRECTA DE ESTILOS CSS (Estilos Inline)
    // Se utiliza la nomenclatura camelCase para propiedades CSS compuestas
    titulo.style.color = "#2ecc71"; // Cambia el color a verde
    titulo.style.backgroundColor = "#f8f9fa"; // Cambia el fondo
    titulo.style.padding = "15px";

    // 4. MEJOR PRÁCTICA: MANIPULACIÓN DE CLASES (classList)
    // En lugar de tocar estilos uno a uno, añadimos una clase CSS predefinida
    boton.classList.add("btn-activo");

    // El método toggle añade la clase si no existe, o la quita si ya existe
    boton.classList.toggle("animacion-pulso");

    console.log("Depuración - Clases actuales del botón:", boton.className);

} else {
    console.log("⚠️ Alerta: No se encontraron los elementos en el árbol DOM actual.");
}
